const d = $json;

const risks = Array.isArray(d.risks) ? d.risks : [];
const recs = Array.isArray(d.recommendations) ? d.recommendations : [];
const actions = Array.isArray(d.agent?.action_queue) ? d.agent.action_queue : [];
const executed = Array.isArray(d.executed_actions) ? d.executed_actions : Array.isArray(d.agent?.execution?.executed_actions) ? d.agent.execution.executed_actions : [];
const memory = d.agent?.memory || {};
const learning = d.agent?.learning || {};
const trend = memory.trend || {};
const outcomeTracking = Array.isArray(d.agent?.tracking?.outcome_tracking) ? d.agent.tracking.outcome_tracking : [];
const outcomeCounts = d.agent?.tracking?.outcome_status_counts || {};
const charts = d.charts || d.raw?.charts || {};
const pieChart = charts.pie?.data_uri || '';
const barChart = charts.bar?.data_uri || '';

const lines = [];
lines.push('Weekly Delivery Health Report');
lines.push(`Generated (UTC): ${d.generated_at_utc || 'N/A'}`);
lines.push(`Sprint Completion: ${d.sprint_completion_pct ?? 'N/A'}%`);
lines.push('');

lines.push('Risks detected:');
if (!risks.length) lines.push('- None');
for (const r of risks.slice(0, 5)) lines.push(`- ${r}`);

lines.push('');
lines.push('Recommendations:');
if (!recs.length) lines.push('- None');
for (const r of recs.slice(0, 3)) lines.push(`- ${r}`);

lines.push('');
lines.push('Agentic action queue (Top 3):');
if (!actions.length) lines.push('- No agent actions generated');
for (const a of actions.slice(0, 3)) {
  const pri = a.priority || 'P3';
  const owner = a.owner || 'Unassigned';
  const objective = a.objective || 'No objective provided';
  lines.push(`- [${pri}] ${objective} (Owner: ${owner})`);
}

lines.push('');
lines.push('Action tracking (Top 3):');
if (!executed.length) lines.push('- No execution records');
for (const e of executed.slice(0, 3)) {
  lines.push(`- ${e.action_id || 'unknown'}: ${e.status || 'unknown'} (${e.detail || 'no detail'})`);
}

lines.push('');
lines.push('Outcome tracking (Last executed actions):');
if (!outcomeTracking.length) lines.push('- No prior executed-action outcomes available yet');
for (const o of outcomeTracking.slice(0, 5)) {
  lines.push(`- ${o.action_id || 'unknown'}: ${o.status || 'unknown'} -> ${o.evidence || 'no evidence'}`);
}

lines.push('');
lines.push('Outcome summary:');
lines.push(`- Resolved: ${outcomeCounts.resolved ?? 0}`);
lines.push(`- Improving: ${outcomeCounts.improving ?? 0}`);
lines.push(`- Pending observation: ${outcomeCounts.pending_observation ?? 0}`);
lines.push(`- Unresolved: ${outcomeCounts.unresolved ?? 0}`);
lines.push(`- Regressed: ${outcomeCounts.regressed ?? 0}`);

lines.push('');
lines.push('State memory:');
lines.push(`- Last completion: ${trend.last_completion ?? 'N/A'}`);
lines.push(`- Current completion: ${trend.current_completion ?? 'N/A'}`);
lines.push(`- Completion delta: ${trend.completion_delta ?? 'N/A'}`);
if (learning.performance_summary) lines.push(`- ${learning.performance_summary}`);
if (Array.isArray(learning.resolved_problems) && learning.resolved_problems.length) {
  lines.push('- Resolved problems:');
  for (const item of learning.resolved_problems.slice(0, 5)) lines.push(`  - ${item}`);
}

lines.push('');
lines.push('Execution summary:');
lines.push(`- Executed: ${d.agent?.execution?.status_counts?.executed ?? 0}`);
lines.push(`- Skipped: ${d.agent?.execution?.status_counts?.skipped ?? 0}`);
lines.push(`- Failed: ${d.agent?.execution?.status_counts?.failed ?? 0}`);
lines.push(`- Dry run: ${d.agent?.execution?.status_counts?.dry_run ?? 0}`);

lines.push('');
lines.push('Weekly Slack summary:');
lines.push(d.weekly_slack_summary || 'No Slack summary available.');

lines.push('');
lines.push('CI/CD:');
lines.push(`- Last Build: ${d.cicd?.last_build || 'unknown'}`);
lines.push(`- UAT: ${d.cicd?.environments?.uat || 'unknown'}`);
lines.push(`- PROD: ${d.cicd?.environments?.prod || 'unknown'}`);

const reportText = lines.join('\n');
const subject = `Weekly Delivery Health - ${new Date().toISOString().slice(0, 10)}`;
const escapeHtml = (value) => String(value).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;').replace(/'/g, '&#39;');
const reportHtml = `
<div style="font-family:Segoe UI,Arial,sans-serif;background:#0f1720;color:#e7f2f7;padding:24px;line-height:1.5;">
  <h1 style="margin:0 0 8px;font-size:26px;">Weekly Delivery Health Report</h1>
  <div style="color:#92a7b2;margin-bottom:18px;">Generated (UTC): ${escapeHtml(d.generated_at_utc || 'N/A')} | Sprint Completion: ${escapeHtml(d.sprint_completion_pct ?? 'N/A')}%</div>

  <h2 style="margin:18px 0 8px;font-size:18px;">Charts</h2>
  <div style="display:grid;gap:16px;grid-template-columns:repeat(auto-fit,minmax(320px,1fr));margin-bottom:20px;">
    <div style="background:#132028;border:1px solid #26404f;border-radius:16px;padding:14px;">
      <div style="font-weight:700;margin-bottom:10px;">Jira Status Overview</div>
      ${pieChart ? `<img src="${pieChart}" alt="Jira status pie chart" style="width:100%;height:auto;border-radius:12px;display:block;" />` : '<div style="color:#92a7b2;">Chart unavailable</div>'}
    </div>
    <div style="background:#132028;border:1px solid #26404f;border-radius:16px;padding:14px;">
      <div style="font-weight:700;margin-bottom:10px;">Status Count by Workflow State</div>
      ${barChart ? `<img src="${barChart}" alt="Jira status bar chart" style="width:100%;height:auto;border-radius:12px;display:block;" />` : '<div style="color:#92a7b2;">Chart unavailable</div>'}
    </div>
  </div>

  <h2 style="margin:18px 0 8px;font-size:18px;">Full Report</h2>
  <pre style="white-space:pre-wrap;background:#132028;border:1px solid #26404f;border-radius:16px;padding:16px;margin:0;font-family:Segoe UI,Arial,sans-serif;">${escapeHtml(reportText)}</pre>
</div>`;

return [{
  json: {
    reportText,
    reportHtml,
    subject
  }
}];
